import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient();

/** Remove all application rows; schema and `_prisma_migrations` are unchanged. */
async function main() {
  if (process.env.NODE_ENV === "production") {
    throw new Error("Refusing to clear data in production (NODE_ENV=production).");
  }

  console.log("[db:clear] deleting application data...");
  await prisma.sessionImportKey.deleteMany();
  await prisma.auditLog.deleteMany();
  await prisma.session.deleteMany();
  await prisma.program.deleteMany();
  await prisma.creator.deleteMany();
  console.log("[db:clear] done (tables empty; schema unchanged).");
}

main()
  .then(async () => {
    await prisma.$disconnect();
  })
  .catch(async (e) => {
    console.error(e);
    await prisma.$disconnect();
    process.exit(1);
  });
